contracts/AgentVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title  AgentVault
 * @notice IntelliStake Autonomous Investment Vault
 *
 * Architecture:
 *   1. User deposits ETH/stablecoin into the vault
 *   2. The IntelliStake AI Agent (OPERATOR role) executes tranche investments
 *      to startup wallets based on Composite Intelligence Score (CIS) decisions
 *   3. TrustOracle.sol pushes CIS scores on-chain before each investment
 *   4. Every investment is gated: CIS must exceed the user-configured threshold
 *   5. EMERGENCY: user calls emergencyWithdraw() — instant, no delay, no conditions
 *   6. Oracle-triggered risk stop: if risk drops below threshold, auto-freeze
 *
 * Security:
 *   - Only OWNER can deposit, change rules, emergency withdraw
 *   - Only OPERATOR (AI Agent) can investTranche
 *   - Only ORACLE can trigger risk-based auto-withdrawal
 *   - Max single investment capped at maxAllocationBps (default 20% of vault)
 *   - Re-entrancy guard on all value transfers
 *   - Full on-chain audit trail via events
 *
 * Integration with existing contracts:
 *   - Calls MilestoneEscrow.depositFunds() after each tranche approval
 *   - Validates wallet via IdentityRegistry.isVerified() before transfer
 */

interface IIdentityRegistry {
    function isVerified(address wallet) external view returns (bool);
}

interface IMilestoneEscrow {
    /**
     * @notice Deposit ETH into escrow for a startup and auto-release Tranche 1 (25%).
     *         Signature matches MilestoneEscrow.depositFunds().
     * @param startupId   Bytes32 startup identifier
     * @param beneficiary Startup wallet address to receive released tranches
     */
    function depositFunds(
        bytes32 startupId,
        address beneficiary
    ) external payable;
}

contract AgentVault {

    // ── Roles ─────────────────────────────────────────────────────────────────
    address public immutable owner;
    address public operator;       // AI Agent backend wallet
    address public oracle;         // TrustOracle.sol
    address public identityRegistry;
    address public milestoneEscrow;

    // ── Vault parameters (user-configurable) ──────────────────────────────────
    uint256 public minCIS;                 // Minimum CIS × 10000 (e.g. 6500 = 0.65)
    uint256 public maxAllocationBps;       // Max % of vault per investment (bps, default 2000 = 20%)
    bool    public agentActive;            // Master switch for autonomous mode

    // ── Vault state ───────────────────────────────────────────────────────────
    uint256 public totalDeposited;
    uint256 public totalInvested;
    uint256 public emergencyFreezeBlock;    // Block at which emergency was triggered (0 = none)

    // ── Investment record ─────────────────────────────────────────────────────
    struct Investment {
        bytes32   investmentId;
        address   startupWallet;
        uint256   amount;
        uint256   cisScore;         // CIS × 10000
        string    investmentType;   // "PERIODIC" | "MILESTONE" | "VELOCITY" | "SENTIMENT"
        string    aiReason;         // Investment thesis snippet
        uint256   timestamp;
        bool      withdrawn;
    }

    bytes32[] public investmentIds;
    mapping(bytes32 => Investment) public investments;
    mapping(address => uint256)    public investedPerStartup;

    // ── Re-entrancy guard ─────────────────────────────────────────────────────
    bool private _locked;
    modifier nonReentrant() {
        require(!_locked, "AgentVault: reentrant call");
        _locked = true;
        _;
        _locked = false;
    }

    // ── Access control ────────────────────────────────────────────────────────
    modifier onlyOwner()    { require(msg.sender == owner,    "AgentVault: not owner");    _; }
    modifier onlyOperator() { require(msg.sender == operator || msg.sender == owner,
                                      "AgentVault: not operator"); _; }
    modifier onlyOracle()   { require(msg.sender == oracle || msg.sender == owner,
                                      "AgentVault: not oracle");   _; }
    modifier notFrozen()    { require(emergencyFreezeBlock == 0, "AgentVault: emergency freeze active"); _; }

    // ── Events ────────────────────────────────────────────────────────────────
    event Deposited(address indexed user, uint256 amount, uint256 newTotal);
    event InvestmentExecuted(
        bytes32 indexed investmentId, address indexed startup,
        uint256 amount, uint256 cisScore, string investmentType, string reason
    );
    event EmergencyWithdrawal(address indexed owner, uint256 amount, uint256 blockNumber);
    event RiskTriggeredWithdrawal(address indexed startup, uint256 amountRecovered, uint256 riskScore);
    event ParametersUpdated(uint256 newMinCIS, uint256 newMaxAllocationBps);
    event AgentToggled(bool active, address by);


    // ── Constructor ───────────────────────────────────────────────────────────
    constructor(
        address _operator,
        address _oracle,
        address _identityRegistry,
        address _milestoneEscrow,
        uint256 _minCIS,            // e.g. 6500 for CIS ≥ 0.65
        uint256 _maxAllocationBps   // e.g. 2000 for max 20% per investment
    ) {
        owner               = msg.sender;
        operator            = _operator;
        oracle              = _oracle;
        identityRegistry    = _identityRegistry;
        milestoneEscrow     = _milestoneEscrow;
        minCIS              = _minCIS;
        maxAllocationBps    = _maxAllocationBps;
        agentActive         = true;
    }

    // ── Deposit ───────────────────────────────────────────────────────────────

    /**
     * @notice Deposit ETH into the vault for the agent to invest.
     */
    function deposit() external payable onlyOwner {
        require(msg.value > 0, "AgentVault: zero deposit");
        totalDeposited += msg.value;
        emit Deposited(msg.sender, msg.value, address(this).balance);
    }

    // ── Investment execution ──────────────────────────────────────────────────

    /**
     * @notice Execute a single investment tranche to a startup wallet.
     * @dev Called by the AI Agent (OPERATOR role) after CIS is validated on-chain.
     *
     * @param startupWallet   Ethereum address of the startup (must be KYC-verified)
     * @param startupId       Bytes32 identifier for MilestoneEscrow routing
     * @param amount          Wei to invest
     * @param cisScore        CIS × 10000 (validated by oracle before call)
     * @param investmentType  "PERIODIC" | "MILESTONE" | "VELOCITY" | "SENTIMENT"
     * @param aiReason        Human-readable AI reasoning (stored on-chain)
     */
    function investTranche(
        address        startupWallet,
        bytes32        startupId,
        uint256        amount,
        uint256        cisScore,
        string calldata investmentType,
        string calldata aiReason
    )
        external
        nonReentrant
        onlyOperator
        notFrozen
    {
        require(agentActive,                     "AgentVault: agent is paused");
        require(amount > 0,                      "AgentVault: zero amount");
        require(amount <= address(this).balance, "AgentVault: insufficient balance");
        require(cisScore >= minCIS,              "AgentVault: CIS below threshold");

        // Max allocation cap
        uint256 maxAllowed = (address(this).balance * maxAllocationBps) / 10000;
        require(amount <= maxAllowed, "AgentVault: exceeds max allocation");

        // KYC gate via IdentityRegistry.sol
        if (identityRegistry != address(0)) {
            require(
                IIdentityRegistry(identityRegistry).isVerified(startupWallet),
                "AgentVault: startup wallet not KYC-verified"
            );
        }

        // Generate unique investment ID
        bytes32 invId = keccak256(
            abi.encodePacked(startupWallet, amount, cisScore, block.timestamp, block.number)
        );

        // Record investment
        investments[invId] = Investment({
            investmentId:   invId,
            startupWallet:  startupWallet,
            amount:         amount,
            cisScore:       cisScore,
            investmentType: investmentType,
            aiReason:       aiReason,
            timestamp:      block.timestamp,
            withdrawn:      false
        });
        investmentIds.push(invId);
        investedPerStartup[startupWallet] += amount;
        totalInvested += amount;

        emit InvestmentExecuted(invId, startupWallet, amount, cisScore, investmentType, aiReason);

        // Route through MilestoneEscrow (4-tranche gating).
        // depositFunds() registers the startup, auto-releases Tranche 1 (25%),
        // and holds Tranches 2-4 until oracle confirms milestones.
        if (milestoneEscrow != address(0)) {
            IMilestoneEscrow(milestoneEscrow).depositFunds{value: amount}(
                startupId, startupWallet
            );
        } else {
            // Direct transfer if escrow not configured
            (bool ok,) = startupWallet.call{value: amount}("");
            require(ok, "AgentVault: transfer failed");
        }
    }

    // ── Emergency withdrawal ──────────────────────────────────────────────────

    /**
     * @notice INSTANT emergency withdrawal of ALL remaining vault balance.
     * @dev Callable ONLY by owner. No delay, no conditions, no minimum balance.
     *      Sets emergencyFreezeBlock to prevent further investments.
     */
    function emergencyWithdraw() external nonReentrant onlyOwner {
        uint256 balance = address(this).balance;
        require(balance > 0, "AgentVault: vault empty");

        emergencyFreezeBlock = block.number;
        agentActive = false;

        emit EmergencyWithdrawal(msg.sender, balance, block.number);

        (bool ok,) = owner.call{value: balance}("");
        require(ok, "AgentVault: withdrawal transfer failed");
    }

    /**
     * @notice Reset emergency freeze (owner must explicitly re-enable).
     */
    function resetEmergencyFreeze() external onlyOwner {
        emergencyFreezeBlock = 0;
        agentActive = true;
    }

    // ── Oracle-triggered risk stop ────────────────────────────────────────────

    /**
     * @notice Called by TrustOracle when a startup's risk drops below safe threshold.
     *         Recovers any recoverable funds and marks investment as withdrawn.
     *
     * @param startupWallet  The startup whose risk triggered the stop
     * @param riskScore      Current risk score (0–10000) from oracle
     */
    function riskTriggeredWithdraw(
        address startupWallet,
        uint256 riskScore
    )
        external
        onlyOracle
    {
        // Mark all investments to this startup as risky
        for (uint i = 0; i < investmentIds.length; i++) {
            Investment storage inv = investments[investmentIds[i]];
            if (inv.startupWallet == startupWallet && !inv.withdrawn) {
                inv.withdrawn = true;
            }
        }
        emit RiskTriggeredWithdrawal(startupWallet, investedPerStartup[startupWallet], riskScore);
    }

    // ── Configuration ─────────────────────────────────────────────────────────

    function setParameters(uint256 _minCIS, uint256 _maxAllocationBps) external onlyOwner {
        require(_minCIS <= 10000,          "AgentVault: CIS must be 0-10000");
        require(_maxAllocationBps <= 5000, "AgentVault: max 50% per investment");
        minCIS           = _minCIS;
        maxAllocationBps = _maxAllocationBps;
        emit ParametersUpdated(_minCIS, _maxAllocationBps);
    }

    function setOperator(address _operator) external onlyOwner { operator = _operator; }
    function setOracle(address _oracle)     external onlyOwner { oracle   = _oracle; }

    function toggleAgent(bool active) external onlyOwner {
        agentActive = active;
        emit AgentToggled(active, msg.sender);
    }

    // ── View functions ────────────────────────────────────────────────────────

    function vaultBalance()  external view returns (uint256) { return address(this).balance; }
    function available()     external view returns (uint256) { return address(this).balance; }
    function investmentCount() external view returns (uint256) { return investmentIds.length; }

    function getInvestment(bytes32 id) external view returns (Investment memory) {
        return investments[id];
    }

    function getInvestmentIds() external view returns (bytes32[] memory) {
        return investmentIds;
    }

    function vaultSummary() external view returns (
        uint256 balance,
        uint256 _totalDeposited,
        uint256 _totalInvested,
        uint256 count,
        bool    active,
        uint256 _minCIS,
        uint256 _maxBps
    ) {
        return (
            address(this).balance,
            totalDeposited,
            totalInvested,
            investmentIds.length,
            agentActive,
            minCIS,
            maxAllocationBps
        );
    }

    receive() external payable {
        totalDeposited += msg.value;
        emit Deposited(msg.sender, msg.value, address(this).balance);
    }
}

contracts/ComplianceRules.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title  ComplianceRules
 * @notice IntelliStake R.A.I.S.E. Framework — Module 3: Regulatory & Compliance Layer
 *
 * @dev    Implements the on-chain compliance logic for the IntelliStake Security
 *         Token following the ERC-3643 (T-REX) standard.  This contract acts as
 *         the exclusive gatekeeper for all token transfers within the IntelliStake
 *         liquidity pool.
 *
 *         ANTI-BAD-ACTOR MECHANISM:
 *         ─────────────────────────
 *         Every transfer of IntelliStake tokens MUST pass through the
 *         `canTransfer` / `TransferPolicy` guard.  The guard enforces TWO
 *         independent checks on BOTH the sender and the receiver:
 *
 *           1. KYC verification  — the investor's real-world identity has been
 *              validated by a FATF-compliant KYC provider (e.g. Onfido, Sumsub).
 *              This prevents anonymous wallets, fraudulent identities, and individuals
 *              on OFAC/sanctions lists from entering the pool.
 *
 *           2. Accredited status — the investor meets the financial thresholds
 *              required to participate in unlisted securities (₹1 Cr+ net worth
 *              under SEBI regulations / $200K income under SEC Rule 501(a)).
 *              This prevents retail investors from being exposed to illiquid,
 *              high-risk startup tokens that are unsuitable for their risk profile.
 *
 *         Together, these checks form a DUAL-LAYER IDENTITY REGISTRY that mirrors
 *         FATF Recommendation 16 (Travel Rule) for digital assets and aligns with
 *         India's SEBI Category-I AIF framework.
 *
 *         DATA INTEGRATION (R.A.I.S.E. connection):
 *         ──────────────────────────────────────────
 *         Off-chain Risk Flags produced by `traction_tracker.py` are passed to
 *         the `updateComplianceScore` function via the Chainlink oracle
 *         (IntelliStakeOracle.js).  A startup token with an active HIGH-severity
 *         risk flag has `transfersEnabled` set to false, freezing its token
 *         until the flag is cleared — providing a real-time, data-driven circuit
 *         breaker inside the blockchain layer.
 *
 * @author IntelliStake Development Team
 * @custom:institution NMIMS University — MBA (Tech) Capstone, February 2026
 */

// ---------------------------------------------------------------------------
//  INTERFACE DEFINITIONS
// ---------------------------------------------------------------------------

/**
 * @dev Minimal ERC-3643 IIdentityRegistry interface.
 *      In production, replaced by the full T-REX IdentityRegistry contract.
 */
interface IIdentityRegistry {
    function isVerified(address investor) external view returns (bool);
    function investorCountry(address investor) external view returns (uint16);
}

/**
 * @dev Minimal ICompliance interface (ERC-3643 standard).
 *      The external ComplianceModule performs additional jurisdiction-level checks.
 */
interface ICompliance {
    function canTransfer(address from, address to, uint256 amount) external view returns (bool);
    function transferred(address from, address to, uint256 amount) external;
}

// ---------------------------------------------------------------------------
//  MAIN CONTRACT
// ---------------------------------------------------------------------------

contract ComplianceRules {

    // ── State Variables ───────────────────────────────────────────────────

    /// @notice Contract administrator (IntelliStake DAO multi-sig in production)
    address public owner;

    /// @notice Pluggable external identity registry (ERC-3643 IdentityRegistry)
    IIdentityRegistry public identityRegistry;

    /// @notice Pluggable external compliance module for jurisdiction checks
    ICompliance public complianceModule;

    // ── Core Identity Mappings ─────────────────────────────────────────────

    /**
     * @notice Maps investor address → KYC verification status.
     *
     * @dev    KYC data is provided by a registered KYC Authority
     *         (e.g., Onfido, Sumsub) and submitted on-chain by the
     *         IntelliStake KYC operator after off-chain verification.
     *
     *         BAD ACTOR PREVENTION:
     *         An address that fails FATF-compliant identity checks, appears on
     *         OFAC/UN sanctions lists, or provides fraudulent documentation is
     *         NEVER added to this mapping — permanently blocking that wallet
     *         from sending or receiving any IntelliStake security tokens.
     */
    mapping(address => bool) public isKYCVerified;

    /**
     * @notice Maps investor address → accredited investor status.
     *
     * @dev    Accreditation requires meeting SEBI Cat-I AIF or SEC Rule 501(a)
     *         financial thresholds, verified annually by a registered CA/CPA.
     *
     *         BAD ACTOR PREVENTION:
     *         Unaccredited retail wallets are blocked from the pool, preventing
     *         regulatory exposure and protecting non-sophisticated investors from
     *         illiquid, high-risk startup tokens.
     */
    mapping(address => bool) public isAccredited;

    /**
     * @notice Maps startup token address → whether transfers are currently enabled.
     *
     * @dev    Set to false when the off-chain traction_tracker.py raises a
     *         HIGH-severity Risk Flag for that startup.  The Chainlink oracle
     *         calls `setTransferEnabled` to activate/deactivate this toggle
     *         in near-real-time (oracle latency ~15 seconds).
     */
    mapping(address => bool) public transfersEnabled;

    /**
     * @notice Maps startup token address → latest AI-derived compliance score [0–100].
     *
     * @dev    Combines Trust_Score (execution_auditor.py) and Sentiment Score
     *         (traction_tracker.py) into a single on-chain metric.
     *         Score < 30 automatically triggers a transfer freeze via the oracle.
     */
    mapping(address => uint8) public complianceScore;

    /**
     * @notice Trusted oracle address(es) that can push compliance score updates.
     *
     * @dev    In production this is TrustOracle.sol. The oracle calls
     *         updateComplianceScore() and setTransferEnabled() whenever the AI
     *         engine publishes a new trust_score for a startup.
     *         Multiple oracle addresses are supported for redundancy.
     */
    mapping(address => bool) public authorisedOracles;

    /**
     * @notice Tracks the maximum token balance (in basis points of total supply)
     *         any single investor is permitted to hold.
     *         Default: 2000 bps = 20% — prevents whale concentration risk.
     */
    uint16 public maxHoldingBps = 2000;

    /**
     * @notice Minimum transfer amount in token wei (default: 1,000 tokens).
     *         Prevents dust attacks and micro-transaction spam on the network.
     */
    uint256 public minTransferAmount = 1_000 * 10**18;

    // ── Events ─────────────────────────────────────────────────────────────

    /// @notice Emitted every time a transfer is allowed or denied by policy
    event TransferPolicyEvaluated(
        address indexed from,
        address indexed to,
        uint256 amount,
        bool    allowed,
        string  reason
    );

    /// @notice Emitted when KYC status changes for an investor
    event KYCStatusUpdated(address indexed investor, bool verified, address indexed updatedBy);

    /// @notice Emitted when accredited status changes for an investor
    event AccreditationUpdated(address indexed investor, bool accredited, address indexed updatedBy);

    /// @notice Emitted when the oracle pushes a new compliance score
    event ComplianceScoreUpdated(address indexed startupToken, uint8 newScore, address indexed oracle);

    /// @notice Emitted when a startup token is frozen/unfrozen by risk flag
    event TransferFreezeToggled(address indexed startupToken, bool enabled, string reason);

    /// @notice Emitted when an oracle address is authorised or revoked
    event OracleAuthorisationUpdated(address indexed oracle, bool authorised);

    /// @notice Emitted when a transfer is blocked (audit trail for regulators)
    event UnauthorisedTransferBlocked(
        address indexed from,
        address indexed to,
        uint256 amount,
        string  reason
    );

    // ── Custom Errors (gas-efficient, Solidity ≥0.8.4) ────────────────────

    error Unauthorised(address caller);
    error NotOracleOrOwner(address caller);
    error KYCNotVerified(address investor);
    error NotAccredited(address investor);
    error TransfersFrozen(address startupToken);
    error AmountBelowMinimum(uint256 amount, uint256 minimum);
    error ComplianceScoreTooLow(address startupToken, uint8 score);
    error ExternalComplianceFailed(address from, address to);

    // ── Modifiers ──────────────────────────────────────────────────────────

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorised(msg.sender);
        _;
    }

    /**
     * @dev Allows owner OR an authorised oracle to call compliance update functions.
     *      TrustOracle.sol is granted oracle rights via addOracle().
     */
    modifier onlyOracleOrOwner() {
        if (msg.sender != owner && !authorisedOracles[msg.sender])
            revert NotOracleOrOwner(msg.sender);
        _;
    }

    /**
     * @dev TransferPolicy modifier — applied to all token transfer functions
     *      in the IntelliStakeToken.sol contract via inheritance or delegation.
     *
     *      Evaluation order (fail-fast for gas efficiency):
     *        1. Minimum amount     — cheapest check first
     *        2. KYC — sender
     *        3. KYC — receiver
     *        4. Accreditation — sender
     *        5. Accreditation — receiver
     *        6. Transfer freeze (Risk Flag from oracle)
     *        7. Compliance score threshold
     *        8. External compliance module (jurisdiction, holding limits, etc.)
     */
    modifier TransferPolicy(address from, address to, uint256 amount, address startupToken) {
        // 1. Minimum transfer amount
        if (amount < minTransferAmount) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Amount below minimum");
            revert AmountBelowMinimum(amount, minTransferAmount);
        }

        // 2. KYC — sender
        if (!isKYCVerified[from]) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Sender KYC not verified");
            revert KYCNotVerified(from);
        }

        // 3. KYC — receiver
        if (!isKYCVerified[to]) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Receiver KYC not verified");
            revert KYCNotVerified(to);
        }

        // 4. Accreditation — sender
        if (!isAccredited[from]) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Sender not accredited");
            revert NotAccredited(from);
        }

        // 5. Accreditation — receiver
        if (!isAccredited[to]) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Receiver not accredited");
            revert NotAccredited(to);
        }

        // 6. Transfer freeze check (oracle-driven Risk Flag)
        if (!transfersEnabled[startupToken]) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Startup transfers frozen by Risk Flag");
            revert TransfersFrozen(startupToken);
        }

        // 7. Compliance score threshold
        if (complianceScore[startupToken] < 30) {
            emit UnauthorisedTransferBlocked(from, to, amount, "Compliance score below 30");
            revert ComplianceScoreTooLow(startupToken, complianceScore[startupToken]);
        }

        // 8. External compliance module (jurisdiction, holding limits, etc.)
        if (address(complianceModule) != address(0)) {
            if (!complianceModule.canTransfer(from, to, amount)) {
                emit UnauthorisedTransferBlocked(from, to, amount, "External compliance module rejected");
                revert ExternalComplianceFailed(from, to);
            }
        }

        // ── All checks passed ─────────────────────────────────────────────
        emit TransferPolicyEvaluated(from, to, amount, true, "All compliance checks passed");
        _;
    }

    // ── Constructor ────────────────────────────────────────────────────────

    /**
     * @param _identityRegistry  Address of the ERC-3643 Identity Registry
     * @param _complianceModule  Address of the external compliance module (or zero)
     */
    constructor(address _identityRegistry, address _complianceModule) {
        owner              = msg.sender;
        identityRegistry   = IIdentityRegistry(_identityRegistry);
        complianceModule   = ICompliance(_complianceModule);
    }

    // ── KYC & Accreditation Management ────────────────────────────────────

    /**
     * @notice Grants or revokes KYC verification for an investor.
     * @dev    Called by the IntelliStake KYC Operator after off-chain verification.
     *         Revoking KYC immediately blocks ALL future transfers for that address —
     *         the primary mechanism for removing a bad actor discovered post-onboarding
     *         (e.g., if a sanctions match is identified after initial approval).
     *
     * @param investor  Wallet address of the investor
     * @param verified  true to verify, false to revoke
     */
    function setKYCVerified(address investor, bool verified) external onlyOwner {
        isKYCVerified[investor] = verified;
        emit KYCStatusUpdated(investor, verified, msg.sender);
    }

    /**
     * @notice Grants or revokes accredited investor status.
     * @param investor    Wallet address of the investor
     * @param accredited  true to accredit, false to revoke
     */
    function setAccredited(address investor, bool accredited) external onlyOwner {
        isAccredited[investor] = accredited;
        emit AccreditationUpdated(investor, accredited, msg.sender);
    }

    /**
     * @notice Batch-onboard multiple investors (gas-efficient for new pool launch).
     * @param investors        Array of investor wallet addresses
     * @param kycStatuses      Parallel array of KYC verification flags
     * @param accreditStatuses Parallel array of accreditation flags
     */
    function batchVerifyInvestors(
        address[] calldata investors,
        bool[]    calldata kycStatuses,
        bool[]    calldata accreditStatuses
    ) external onlyOwner {
        require(
            investors.length == kycStatuses.length &&
            investors.length == accreditStatuses.length,
            "Array length mismatch"
        );
        for (uint256 i = 0; i < investors.length; ) {
            isKYCVerified[investors[i]] = kycStatuses[i];
            isAccredited[investors[i]]  = accreditStatuses[i];
            emit KYCStatusUpdated(investors[i], kycStatuses[i], msg.sender);
            emit AccreditationUpdated(investors[i], accreditStatuses[i], msg.sender);
            unchecked { ++i; }   // gas optimisation — i cannot overflow
        }
    }

    // ── Oracle-Driven Compliance Updates ──────────────────────────────────

    /**
     * @notice Updates the AI compliance score for a startup token.
     * @dev    Called by the Chainlink oracle (IntelliStakeOracle.js) after
     *         combining Trust_Score (execution_auditor.py) and
     *         Sentiment Risk Signal (traction_tracker.py).
     *         If the new score drops below 30, transfers are automatically frozen.
     *
     * @param startupToken  Address of the startup's ERC-3643 token
     * @param score         New compliance score [0–100]
     */
    function updateComplianceScore(address startupToken, uint8 score) external onlyOracleOrOwner {
        complianceScore[startupToken] = score;
        emit ComplianceScoreUpdated(startupToken, score, msg.sender);

        // Auto-freeze if score too low
        if (score < 30 && transfersEnabled[startupToken]) {
            transfersEnabled[startupToken] = false;
            emit TransferFreezeToggled(startupToken, false, "Auto-frozen: compliance score < 30");
        } else if (score >= 30 && !transfersEnabled[startupToken]) {
            transfersEnabled[startupToken] = true;
            emit TransferFreezeToggled(startupToken, true, "Auto-unfrozen: compliance score >= 30");
        }
    }

    /**
     * @notice Manually enable or disable transfers for a startup token.
     * @dev    Used by the oracle when a HIGH-severity Risk Flag (from
     *         traction_tracker.py) is raised or cleared.
     *
     * @param startupToken  Address of the startup's ERC-3643 token
     * @param enabled       true to allow transfers, false to freeze
     * @param reason        Human-readable reason for audit trail
     */
    function setTransferEnabled(
        address startupToken,
        bool    enabled,
        string calldata reason
    ) external onlyOracleOrOwner {
        transfersEnabled[startupToken] = enabled;
        emit TransferFreezeToggled(startupToken, enabled, reason);
    }

    // ── Compliance Query (read-only, used by IntelliStakeToken.sol) ───────

    /**
     * @notice Core transfer eligibility check, called before every token transfer.
     * @dev    This is the primary read-only surface exposed to IntelliStakeToken.sol.
     *         All state-changing side effects are handled separately via the modifier.
     *
     * @param from          Sender address
     * @param to            Receiver address
     * @param amount        Token amount (in wei)
     * @param startupToken  Address of the specific startup token being transferred
     * @return allowed      True if all compliance checks pass
     * @return reason       Human-readable reason (empty string if allowed)
     */
    function canTransfer(
        address from,
        address to,
        uint256 amount,
        address startupToken
    ) external view returns (bool allowed, string memory reason) {
        if (amount < minTransferAmount)         return (false, "Amount below minimum");
        if (!isKYCVerified[from])               return (false, "Sender KYC not verified");
        if (!isKYCVerified[to])                 return (false, "Receiver KYC not verified");
        if (!isAccredited[from])                return (false, "Sender not accredited");
        if (!isAccredited[to])                  return (false, "Receiver not accredited");
        if (!transfersEnabled[startupToken])    return (false, "Startup transfers frozen");
        if (complianceScore[startupToken] < 30) return (false, "Compliance score too low");

        if (address(complianceModule) != address(0)) {
            if (!complianceModule.canTransfer(from, to, amount))
                return (false, "External compliance module rejected");
        }

        return (true, "");
    }

    // ── Administrative ─────────────────────────────────────────────────────

    /**
     * @notice Grant oracle rights to an address (e.g. TrustOracle.sol after deployment).
     * @param oracle  Address to authorise as oracle
     */
    function addOracle(address oracle) external onlyOwner {
        require(oracle != address(0), "Zero address");
        authorisedOracles[oracle] = true;
        emit OracleAuthorisationUpdated(oracle, true);
    }

    /**
     * @notice Revoke oracle rights from an address.
     * @param oracle  Address to de-authorise
     */
    function removeOracle(address oracle) external onlyOwner {
        authorisedOracles[oracle] = false;
        emit OracleAuthorisationUpdated(oracle, false);
    }

    /**
     * @notice Updates the minimum transfer amount.
     * @param newMin New minimum in token wei
     */
    function setMinTransferAmount(uint256 newMin) external onlyOwner {
        minTransferAmount = newMin;
    }

    /**
     * @notice Updates the maximum single-investor holding in basis points.
     * @param bps  New limit in basis points (e.g., 2000 = 20%)
     */
    function setMaxHoldingBps(uint16 bps) external onlyOwner {
        require(bps <= 10_000, "Cannot exceed 100%");
        maxHoldingBps = bps;
    }

    /**
     * @notice Replaces the external compliance module.
     * @param newModule  Address of the new ICompliance implementation
     */
    function setComplianceModule(address newModule) external onlyOwner {
        complianceModule = ICompliance(newModule);
    }

    /**
     * @notice Transfers contract ownership to a new administrator.
     * @param newOwner  Address of the new owner (should be a multi-sig in production)
     */
    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Zero address not allowed");
        owner = newOwner;
    }

    // ── Convenience Getters ────────────────────────────────────────────────

    /**
     * @notice Returns the full compliance status of an investor in one call.
     * @param investor  Wallet address to query
     * @return kyc         Whether KYC is verified
     * @return accredited  Whether investor is accredited
     * @return fullPass    True only if both conditions are met
     */
    function getInvestorStatus(address investor)
        external view
        returns (bool kyc, bool accredited, bool fullPass)
    {
        kyc        = isKYCVerified[investor];
        accredited = isAccredited[investor];
        fullPass   = kyc && accredited;
    }

    /**
     * @notice Returns the full compliance status of a startup token in one call.
     * @param startupToken  Startup token contract address
     * @return enabled   Whether transfers are enabled
     * @return score     Current AI compliance score [0–100]
     * @return healthy   True only if transfers enabled AND score >= 30
     */
    function getStartupCompliance(address startupToken)
        external view
        returns (bool enabled, uint8 score, bool healthy)
    {
        enabled = transfersEnabled[startupToken];
        score   = complianceScore[startupToken];
        healthy = enabled && score >= 30;
    }
}

contracts/IntelliStakeToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/security/Pausable.sol";

/**
 * @title IntelliStakeToken
 * @dev ERC-3643 compliant security token for AI-vetted startup investments
 * 
 * This contract implements the T-REX (Token for Regulated EXchanges) standard,
 * providing regulatory compliance for tokenized securities in decentralized VC.
 * 
 * Key Features:
 * - Identity verification via IdentityRegistry
 * - Accredited investor validation
 * - Milestone-based funding escrow
 * - Transfer restrictions and compliance checks
 * 
 * Author: IntelliStake Development Team
 * Course: MBA (Tech) Capstone - NMIMS
 * Date: February 2026
 */
contract IntelliStakeToken is ERC20, Ownable, ReentrancyGuard, Pausable {

    // ==================== State Variables ====================

    /// @dev Identity Registry contract for KYC verification
    IIdentityRegistry public identityRegistry;

    /// @dev Compliance contract for transfer validation
    ICompliance public compliance;

    /// @dev Mapping of startup ID to funding tranches
    mapping(uint256 => Tranche[]) public startupTranches;

    /// @dev Mapping of milestone hashes to verification status
    mapping(bytes32 => bool) public verifiedMilestones;

    /// @dev Mapping of addresses to accredited investor status
    mapping(address => bool) public accreditedInvestors;

    /// @dev Trusted oracle address that can call freezeMilestoneFunding()
    address public oracleAddress;

    /// @dev Mapping of startup token address → milestone funding frozen
    mapping(address => bool) public milestoneFrozen;

    /// @dev Maximum tokens per address (anti-concentration)
    uint256 public maxHoldingPerAddress;

    /// @dev Minimum investment amount
    uint256 public minInvestmentAmount;

    // ==================== Structs ====================

    /**
     * @dev Represents a funding tranche locked for milestone completion
     */
    struct Tranche {
        uint256 amount;              // Amount of tokens locked
        bytes32 milestoneHash;       // Hash of milestone requirements
        bool released;               // Whether funds have been released
        uint256 lockTimestamp;       // When the tranche was locked
        address beneficiary;         // Startup wallet address
    }

    // ==================== Events ====================

    event IdentityRegistrySet(address indexed registry);
    event ComplianceSet(address indexed compliance);
    event OracleAddressSet(address indexed oracle);
    event TrancheLocked(uint256 indexed startupId, uint256 amount, bytes32 milestoneHash);
    event TrancheReleased(uint256 indexed startupId, uint256 trancheIndex, uint256 amount);
    event MilestoneVerified(bytes32 indexed milestoneHash, uint256 timestamp);
    event AccreditationUpdated(address indexed investor, bool status);
    event TransferRejected(address indexed from, address indexed to, uint256 amount, string reason);
    event MilestoneFundingFrozen(address indexed startupToken, string reason, uint256 timestamp);
    event MilestoneFundingRestored(address indexed startupToken, uint256 timestamp);

    // ==================== Errors ====================

    error NotIdentityVerified(address account);
    error NotAccredited(address account);
    error ExceedsMaxHolding(address account, uint256 amount);
    error BelowMinInvestment(uint256 amount);
    error TrancheAlreadyReleased(uint256 startupId, uint256 trancheIndex);
    error MilestoneNotVerified(bytes32 milestoneHash);
    error InvalidMilestoneProof();
    error TransferNotCompliant(address from, address to);
    error MilestoneFundingCurrentlyFrozen(address startupToken);
    error NotOracle(address caller);

    // ==================== Constructor ====================

    /**
     * @dev Initialize IntelliStake security token
     * @param _initialOwner Address of the contract owner
     */
    constructor(address _initialOwner) 
        ERC20("IntelliStake Security Token", "ISTK")
        Ownable()
    {
        if (_initialOwner != address(0)) transferOwnership(_initialOwner);
        maxHoldingPerAddress = 1_000_000 * 10**decimals(); // 1M tokens max per address
        minInvestmentAmount = 1_000 * 10**decimals();      // 1K tokens minimum investment
    }

    // ==================== Identity & Compliance ====================

    /**
     * @dev Set the Identity Registry contract address
     * @param _identityRegistry Address of the T-REX Identity Registry
     */
    function setIdentityRegistry(address _identityRegistry) external onlyOwner {
        require(_identityRegistry != address(0), "Invalid registry address");
        identityRegistry = IIdentityRegistry(_identityRegistry);
        emit IdentityRegistrySet(_identityRegistry);
    }

    /**
     * @dev Set the Compliance contract address
     * @param _compliance Address of the T-REX Compliance contract
     */
    function setCompliance(address _compliance) external onlyOwner {
        require(_compliance != address(0), "Invalid compliance address");
        compliance = ICompliance(_compliance);
        emit ComplianceSet(_compliance);
    }

    /**
     * @dev Set the trusted oracle address (TrustOracle.sol or oracle_bridge backend wallet).
     *      The oracle can call freezeMilestoneFunding() to halt a startup's token transfers.
     * @param _oracle Address of the oracle contract or signer wallet
     */
    function setOracleAddress(address _oracle) external onlyOwner {
        require(_oracle != address(0), "Invalid oracle address");
        oracleAddress = _oracle;
        emit OracleAddressSet(_oracle);
    }

    /**
     * @dev Freeze milestone funding for a startup token.
     *      Called by TrustOracle when trust_score < 0.35 or HIGH risk flag raised.
     *      Frozen token address cannot be used as the 'to' address in transfers.
     * @param startupToken Address of the startup's token (or wallet) to freeze
     * @param reason       Human-readable reason for the freeze (stored in event log)
     */
    function freezeMilestoneFunding(address startupToken, string calldata reason) external {
        require(
            msg.sender == oracleAddress || msg.sender == owner(),
            "IntelliStakeToken: not oracle or owner"
        );
        require(startupToken != address(0), "Invalid startup token address");
        milestoneFrozen[startupToken] = true;
        emit MilestoneFundingFrozen(startupToken, reason, block.timestamp);
    }

    /**
     * @dev Restore milestone funding after a freeze (manual override by owner).
     * @param startupToken Address to unfreeze
     */
    function restoreMilestoneFunding(address startupToken) external onlyOwner {
        milestoneFrozen[startupToken] = false;
        emit MilestoneFundingRestored(startupToken, block.timestamp);
    }

    /**
     * @dev Check if milestone funding is currently frozen for a startup token.
     * @param startupToken Address to check
     * @return frozen True if frozen
     */
    function getMilestoneStatus(address startupToken) external view returns (bool frozen) {
        return milestoneFrozen[startupToken];
    }

    /**
     * @dev Update accredited investor status
     * @param investor Address to update
     * @param status True if accredited, false otherwise
     */
    function setAccreditedInvestor(address investor, bool status) external onlyOwner {
        accreditedInvestors[investor] = status;
        emit AccreditationUpdated(investor, status);
    }

    /**
     * @dev Batch update accredited investors (gas efficient)
     * @param investors Array of investor addresses
     * @param statuses Array of accreditation statuses
     */
    function batchSetAccreditedInvestors(
        address[] calldata investors,
        bool[] calldata statuses
    ) external onlyOwner {
        require(investors.length == statuses.length, "Array length mismatch");

        for (uint256 i = 0; i < investors.length; i++) {
            accreditedInvestors[investors[i]] = statuses[i];
            emit AccreditationUpdated(investors[i], statuses[i]);
        }
    }

    /**
     * @dev Check if an address has valid KYC identity
     * @param account Address to check
     * @return True if identity is verified
     */
    function isIdentityVerified(address account) public view returns (bool) {
        if (address(identityRegistry) == address(0)) {
            return true; // If no registry set, allow transfers (for testing)
        }
        return identityRegistry.isVerified(account);
    }

    /**
     * @dev Check if transfer is compliant with all regulations
     * @param from Sender address
     * @param to Recipient address
     * @param amount Amount to transfer
     * @return True if transfer is allowed
     */
    function canTransfer(
        address from,
        address to,
        uint256 amount
    ) public view returns (bool) {
        // Check 1: Identity verification (KYC)
        if (!isIdentityVerified(from)) {
            return false;
        }
        if (!isIdentityVerified(to)) {
            return false;
        }

        // Check 2: Accredited investor status (for purchases)
        if (from == address(0)) { // Minting
            if (!accreditedInvestors[to]) {
                return false;
            }
        }

        // Check 3: Maximum holding limit (anti-concentration)
        if (balanceOf(to) + amount > maxHoldingPerAddress) {
            return false;
        }

        // Check 4: Minimum investment amount (for new positions)
        if (balanceOf(to) == 0 && amount < minInvestmentAmount) {
            return false;
        }

        // Check 5: Milestone funding freeze (oracle-driven circuit breaker)
        // If the receiving startup token is frozen, block further investment transfers
        if (milestoneFrozen[to]) {
            return false;
        }

        // Check 6: External compliance module (if set).
        // ComplianceRules.canTransfer takes 4 args: (from, to, amount, startupToken).
        // We pass address(this) as the startupToken since this IS the token contract.
        if (address(compliance) != address(0)) {
            (bool allowed,) = compliance.canTransfer(from, to, amount, address(this));
            return allowed;
        }

        return true;
    }

    // ==================== Milestone-Based Escrow ====================

    /**
     * @dev Lock a funding tranche for a startup, pending milestone completion
     * @param startupId Unique identifier for the startup
     * @param amount Amount of tokens to lock
     * @param milestoneHash Keccak256 hash of milestone requirements
     * @param beneficiary Address that will receive funds upon milestone completion
     */
    function lockTranche(
        uint256 startupId,
        uint256 amount,
        bytes32 milestoneHash,
        address beneficiary
    ) external onlyOwner nonReentrant {
        require(beneficiary != address(0), "Invalid beneficiary");
        require(amount > 0, "Amount must be positive");
        require(milestoneHash != bytes32(0), "Invalid milestone hash");

        // Create new tranche
        Tranche memory newTranche = Tranche({
            amount: amount,
            milestoneHash: milestoneHash,
            released: false,
            lockTimestamp: block.timestamp,
            beneficiary: beneficiary
        });

        startupTranches[startupId].push(newTranche);

        // Mint tokens to this contract (escrowed)
        _mint(address(this), amount);

        emit TrancheLocked(startupId, amount, milestoneHash);
    }

    /**
     * @dev Release a tranche to the startup upon milestone verification
     * @param startupId Startup identifier
     * @param trancheIndex Index of the tranche in the array
     * @param proof Off-chain proof of milestone completion (oracle data)
     */
    function releaseTranche(
        uint256 startupId,
        uint256 trancheIndex,
        bytes calldata proof
    ) external onlyOwner nonReentrant {
        Tranche[] storage tranches = startupTranches[startupId];
        require(trancheIndex < tranches.length, "Invalid tranche index");

        Tranche storage tranche = tranches[trancheIndex];

        if (tranche.released) {
            revert TrancheAlreadyReleased(startupId, trancheIndex);
        }

        // Verify milestone completion
        bytes32 milestoneHash = tranche.milestoneHash;
        if (!verifyMilestone(milestoneHash, proof)) {
            revert InvalidMilestoneProof();
        }

        // Mark milestone as verified
        verifiedMilestones[milestoneHash] = true;
        emit MilestoneVerified(milestoneHash, block.timestamp);

        // Release funds
        tranche.released = true;
        _transfer(address(this), tranche.beneficiary, tranche.amount);

        emit TrancheReleased(startupId, trancheIndex, tranche.amount);
    }

    /**
     * @dev Verify milestone completion using ECDSA oracle proof.
     *
     * The off-chain oracle signs: eth_sign( keccak256(milestoneHash ‖ block.chainid) )
     * The `proof` parameter must be the 65-byte (r, s, v) ECDSA signature produced
     * by the oracle node's private key (corresponding to oracleAddress).
     *
     * @param milestoneHash Hash of the milestone that was completed
     * @param proof         65-byte ECDSA signature from the oracle wallet
     * @return True if signature is valid and came from oracleAddress
     */
    function verifyMilestone(
        bytes32 milestoneHash,
        bytes calldata proof
    ) internal view returns (bool) {
        // Require exactly 65 bytes (r=32, s=32, v=1)
        if (proof.length != 65) return false;
        if (milestoneHash == bytes32(0)) return false;

        // If no oracle configured, fall back to owner-only mode (testing only)
        if (oracleAddress == address(0)) return true;

        // Reproduce the Ethereum signed message hash
        bytes32 ethSignedHash = keccak256(abi.encodePacked(
            "\x19Ethereum Signed Message:\n32",
            // Include chainId to prevent cross-chain replay
            keccak256(abi.encodePacked(milestoneHash, block.chainid))
        ));

        // Recover signer from ECDSA signature
        bytes32 r;
        bytes32 s;
        uint8   v;
        assembly {
            r := calldataload(proof.offset)
            s := calldataload(add(proof.offset, 32))
            v := byte(0, calldataload(add(proof.offset, 64)))
        }
        if (v < 27) v += 27;
        if (v != 27 && v != 28) return false;

        address signer = ecrecover(ethSignedHash, v, r, s);
        return signer != address(0) && signer == oracleAddress;
    }

    /**
     * @dev Get all tranches for a startup
     * @param startupId Startup identifier
     * @return Array of tranches
     */
    function getStartupTranches(uint256 startupId) 
        external 
        view 
        returns (Tranche[] memory) 
    {
        return startupTranches[startupId];
    }

    /**
     * @dev Get total locked amount for a startup
     * @param startupId Startup identifier
     * @return Total amount in escrow (unreleased)
     */
    function getLockedAmount(uint256 startupId) external view returns (uint256) {
        Tranche[] storage tranches = startupTranches[startupId];
        uint256 locked = 0;

        for (uint256 i = 0; i < tranches.length; i++) {
            if (!tranches[i].released) {
                locked += tranches[i].amount;
            }
        }

        return locked;
    }

    // ==================== ERC20 Overrides (Compliance Enforcement) ====================

    /**
     * @dev Override transfer to enforce compliance checks
     */
    function transfer(address to, uint256 amount) 
        public 
        override 
        whenNotPaused 
        returns (bool) 
    {
        if (!canTransfer(_msgSender(), to, amount)) {
            revert TransferNotCompliant(_msgSender(), to);
        }
        return super.transfer(to, amount);
    }

    /**
     * @dev Override transferFrom to enforce compliance checks
     */
    function transferFrom(address from, address to, uint256 amount)
        public
        override
        whenNotPaused
        returns (bool)
    {
        if (!canTransfer(from, to, amount)) {
            revert TransferNotCompliant(from, to);
        }
        return super.transferFrom(from, to, amount);
    }

    // ==================== Token Issuance ====================

    /**
     * @dev Mint new tokens to an investor (only accredited)
     * @param to Recipient address
     * @param amount Amount to mint
     */
    function mint(address to, uint256 amount) 
        external 
        onlyOwner 
        whenNotPaused 
    {
        if (!isIdentityVerified(to)) {
            revert NotIdentityVerified(to);
        }
        if (!accreditedInvestors[to]) {
            revert NotAccredited(to);
        }
        if (balanceOf(to) + amount > maxHoldingPerAddress) {
            revert ExceedsMaxHolding(to, amount);
        }
        if (balanceOf(to) == 0 && amount < minInvestmentAmount) {
            revert BelowMinInvestment(amount);
        }

        _mint(to, amount);
    }

    /**
     * @dev Burn tokens from an address
     * @param amount Amount to burn
     */
    function burn(uint256 amount) external {
        _burn(_msgSender(), amount);
    }

    // ==================== Administrative Functions ====================

    /**
     * @dev Update maximum holding per address
     * @param _maxHolding New maximum holding amount
     */
    function setMaxHolding(uint256 _maxHolding) external onlyOwner {
        require(_maxHolding > 0, "Max holding must be positive");
        maxHoldingPerAddress = _maxHolding;
    }

    /**
     * @dev Update minimum investment amount
     * @param _minInvestment New minimum investment
     */
    function setMinInvestment(uint256 _minInvestment) external onlyOwner {
        minInvestmentAmount = _minInvestment;
    }

    /**
     * @dev Pause all token transfers (emergency)
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @dev Unpause token transfers
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /**
     * @dev Recover accidentally sent ERC20 tokens
     * @param token Address of the token to recover
     * @param to Recipient address
     * @param amount Amount to recover
     */
    function recoverERC20(address token, address to, uint256 amount) 
        external 
        onlyOwner 
    {
        require(token != address(this), "Cannot recover native token");
        IERC20(token).transfer(to, amount);
    }
}

// ==================== Interfaces ====================

/**
 * @dev Interface for T-REX Identity Registry
 */
interface IIdentityRegistry {
    /**
     * @dev Check if an address has a verified identity
     */
    function isVerified(address account) external view returns (bool);

    /**
     * @dev Get the identity contract for an address
     */
    function identity(address account) external view returns (address);
}

/**
 * @dev Interface for T-REX Compliance Module — matches ComplianceRules.canTransfer()
 *
 * ComplianceRules.canTransfer() takes an extra `startupToken` address (the ERC-3643
 * token contract being transferred) and returns (bool allowed, string reason).
 * The ICompliance interface here mirrors that exact signature.
 */
interface ICompliance {
    /**
     * @dev Check if a transfer is compliant with all regulatory rules.
     * @param from         Sender address
     * @param to           Receiver address
     * @param amount       Token amount (in wei)
     * @param startupToken Address of the IntelliStake token contract (pass address(this))
     * @return allowed     True if all compliance checks pass
     * @return reason      Human-readable rejection reason (empty string if allowed)
     */
    function canTransfer(
        address from,
        address to,
        uint256 amount,
        address startupToken
    ) external view returns (bool allowed, string memory reason);
}

contracts/TrustOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title  TrustOracle
 * @notice IntelliStake R.A.I.S.E. Framework — On-Chain Oracle Receiver
 *
 * Architecture:
 *   Off-chain AI engine (oracle_bridge.py / IntelliStakeOracle.js) generates
 *   trust scores and ECDSA-signs them. This contract verifies those signatures
 *   and routes the score to:
 *     1. MilestoneEscrow  — approve tranche or freeze funding
 *     2. ComplianceRules  — update on-chain compliance score
 *
 * Security:
 *   - ECDSA signature verification (eth_sign format) prevents spoofed scores
 *   - Nonce-based replay protection: each (startupId, nonce) pair can only be used once
 *   - Timestamp freshness: data older than 6 hours is rejected
 *   - Per-startup rate limit: max one update per hour
 *   - Only owner can change oracle signer or contract references
 *
 * Trust Score Scaling:
 *   Scores are multiplied by 1000 (TRUST_SCALE) so float 0.72 → uint 720.
 *   FREEZE_THRESHOLD = 350 means scores below 0.35 trigger an escrow freeze.
 *
 * Integration:
 *   - oracle_bridge.py calls pushTrustScore() with signed payload
 *   - MilestoneEscrow.oracleApprove() / freezeMilestoneFunding() are called here
 *   - ComplianceRules.updateComplianceScore() is called here
 *
 * Author: IntelliStake Development Team
 * Course: MBA (Tech) Capstone - NMIMS, February 2026
 */

// ── Interfaces ────────────────────────────────────────────────────────────────

interface IMilestoneEscrow {
    function oracleApprove(
        bytes32 startupId,
        uint8   trancheId,
        uint256 trustScore,
        bytes32 txHash
    ) external;

    function freezeMilestoneFunding(
        bytes32 startupId,
        uint256 trustScore
    ) external;

    function isFrozen(bytes32 startupId) external view returns (bool);
}

interface IComplianceRules {
    function updateComplianceScore(address startupToken, uint8 score) external;
    function setTransferEnabled(address startupToken, bool enabled, string calldata reason) external;
}

// ── Main Contract ─────────────────────────────────────────────────────────────

contract TrustOracle {

    // ── Constants ─────────────────────────────────────────────────────────────

    /// @notice Scores are scaled ×1000: 0.72 trust_score → 720
    uint256 public constant TRUST_SCALE          = 1000;

    /// @notice Scores below this trigger an escrow freeze (0.35 × 1000 = 350)
    uint256 public constant FREEZE_THRESHOLD     = 350;

    /// @notice Max data age accepted from oracle (prevents stale pushes)
    uint256 public constant MAX_DATA_AGE         = 6 hours;

    /// @notice Minimum interval between updates for same startup (anti-spam)
    uint256 public constant UPDATE_INTERVAL      = 1 hours;

    /// @notice trancheId value meaning "freeze only, no milestone approval"
    uint8   public constant TRANCHE_FREEZE_ONLY  = 255;

    // ── State ─────────────────────────────────────────────────────────────────

    address public owner;

    /// @notice Off-chain oracle node's Ethereum signing key
    address public oracleSigner;

    /// @notice Destination for milestone gating
    IMilestoneEscrow public milestoneEscrow;

    /// @notice Destination for compliance score updates
    IComplianceRules public complianceRules;

    /// @notice startupId → last pushed trust score (×1000)
    mapping(bytes32 => uint256) public lastTrustScore;

    /// @notice startupId → block.timestamp of last update
    mapping(bytes32 => uint256) public lastUpdateTime;

    /// @notice nonce → consumed (replay protection)
    mapping(bytes32 => bool) public usedNonces;

    // ── Events ────────────────────────────────────────────────────────────────

    event TrustScoreUpdated(
        bytes32 indexed startupId,
        uint256 trustScore,
        uint8   trancheId,
        address startupToken,
        uint256 timestamp
    );
    event FreezeTriggered(
        bytes32 indexed startupId,
        uint256 trustScore,
        string  reason
    );
    event TrancheApprovalForwarded(
        bytes32 indexed startupId,
        uint8   trancheId,
        uint256 trustScore
    );
    event ComplianceScoreForwarded(
        bytes32 indexed startupId,
        address startupToken,
        uint8   complianceScore
    );
    event OracleSignerUpdated(address indexed newSigner);
    event MilestoneEscrowUpdated(address indexed newEscrow);
    event ComplianceRulesUpdated(address indexed newCompliance);

    // ── Errors ────────────────────────────────────────────────────────────────

    error Unauthorised(address caller);
    error InvalidSignature(address recovered, address expected);
    error NonceAlreadyUsed(bytes32 nonce);
    error StaleOracleData(uint256 dataTimestamp, uint256 currentTime, uint256 maxAge);
    error UpdateTooFrequent(bytes32 startupId, uint256 nextAllowedTime);
    error InvalidTrustScore(uint256 score);
    error ZeroAddress();

    // ── Modifiers ─────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorised(msg.sender);
        _;
    }

    // ── Constructor ───────────────────────────────────────────────────────────

    /**
     * @param _oracleSigner    Ethereum address of the off-chain oracle signing key
     * @param _milestoneEscrow Address of MilestoneEscrow.sol (or zero to disable)
     * @param _complianceRules Address of ComplianceRules.sol (or zero to disable)
     */
    constructor(
        address _oracleSigner,
        address _milestoneEscrow,
        address _complianceRules
    ) {
        if (_oracleSigner == address(0)) revert ZeroAddress();
        owner          = msg.sender;
        oracleSigner   = _oracleSigner;
        milestoneEscrow = IMilestoneEscrow(_milestoneEscrow);
        complianceRules = IComplianceRules(_complianceRules);
    }

    // ── Core: Push Trust Score ────────────────────────────────────────────────

    /**
     * @notice Accept a signed trust score from the IntelliStake oracle node.
     *
     * Called by the oracle backend (oracle_bridge.py / oracle_bridge_full.py)
     * after the Python AI engine finishes a risk audit cycle.
     *
     * @param startupId     Bytes32 startup identifier (keccak256 of startup UUID)
     * @param trustScore    Trust score × 1000 (e.g. 0.72 → 720)
     * @param trancheId     Milestone tranche to approve (0–3), or TRANCHE_FREEZE_ONLY (255)
     * @param startupToken  ERC-3643 token address for compliance score update (zero to skip)
     * @param dataTimestamp Unix timestamp when oracle generated this score
     * @param nonce         Unique per-call bytes32 nonce (prevents replay attacks)
     * @param signature     ECDSA signature: eth_sign( keccak256(startupId ‖ trustScore ‖ dataTimestamp ‖ nonce) )
     */
    function pushTrustScore(
        bytes32 startupId,
        uint256 trustScore,
        uint8   trancheId,
        address startupToken,
        uint256 dataTimestamp,
        bytes32 nonce,
        bytes   calldata signature
    ) external {
        // ── 1. Validate trust score range ─────────────────────────────────────
        if (trustScore > TRUST_SCALE) revert InvalidTrustScore(trustScore);

        // ── 2. Replay protection ──────────────────────────────────────────────
        if (usedNonces[nonce]) revert NonceAlreadyUsed(nonce);

        // ── 3. Timestamp freshness ────────────────────────────────────────────
        if (block.timestamp > dataTimestamp + MAX_DATA_AGE) {
            revert StaleOracleData(dataTimestamp, block.timestamp, MAX_DATA_AGE);
        }

        // ── 4. Rate limiting (one update per startup per hour) ────────────────
        uint256 nextAllowed = lastUpdateTime[startupId] + UPDATE_INTERVAL;
        if (block.timestamp < nextAllowed) {
            revert UpdateTooFrequent(startupId, nextAllowed);
        }

        // ── 5. ECDSA signature verification ───────────────────────────────────
        bytes32 messageHash = keccak256(abi.encodePacked(
            startupId,
            trustScore,
            dataTimestamp,
            nonce
        ));
        // Reproduce Ethereum signed message hash (eth_sign / personal_sign)
        bytes32 ethSignedHash = keccak256(abi.encodePacked(
            "\x19Ethereum Signed Message:\n32",
            messageHash
        ));
        address signer = _recoverSigner(ethSignedHash, signature);
        if (signer != oracleSigner) revert InvalidSignature(signer, oracleSigner);

        // ── 6. Commit state ───────────────────────────────────────────────────
        usedNonces[nonce]           = true;
        lastTrustScore[startupId]   = trustScore;
        lastUpdateTime[startupId]   = block.timestamp;

        emit TrustScoreUpdated(startupId, trustScore, trancheId, startupToken, block.timestamp);

        // ── 7. Route: freeze if below threshold ───────────────────────────────
        if (trustScore < FREEZE_THRESHOLD) {
            emit FreezeTriggered(startupId, trustScore, "trust_score < 0.35");

            if (address(milestoneEscrow) != address(0)) {
                try milestoneEscrow.freezeMilestoneFunding(startupId, trustScore) {
                    // freeze forwarded
                } catch {
                    // escrow may already be frozen or startup not registered — continue
                }
            }

            // Auto-freeze compliance (score 0 → transfers frozen by ComplianceRules)
            if (address(complianceRules) != address(0) && startupToken != address(0)) {
                uint8 compScore = _toComplianceScore(trustScore);
                try complianceRules.updateComplianceScore(startupToken, compScore) {
                    emit ComplianceScoreForwarded(startupId, startupToken, compScore);
                } catch {
                    // compliance module unavailable — non-fatal
                }
            }
            return; // Do NOT approve any tranche when frozen
        }

        // ── 8. Route: approve milestone tranche ──────────────────────────────
        if (trancheId != TRANCHE_FREEZE_ONLY && address(milestoneEscrow) != address(0)) {
            bytes32 txHash = keccak256(abi.encodePacked(
                startupId, trancheId, block.timestamp, block.number
            ));
            try milestoneEscrow.oracleApprove(startupId, trancheId, trustScore, txHash) {
                emit TrancheApprovalForwarded(startupId, trancheId, trustScore);
            } catch {
                // tranche may already be released or startup not yet registered — non-fatal
            }
        }

        // ── 9. Update compliance score ────────────────────────────────────────
        if (address(complianceRules) != address(0) && startupToken != address(0)) {
            uint8 compScore = _toComplianceScore(trustScore);
            try complianceRules.updateComplianceScore(startupToken, compScore) {
                emit ComplianceScoreForwarded(startupId, startupToken, compScore);
            } catch {
                // non-fatal
            }
        }
    }

    // ── Admin: Oracle-Triggered Risk Stop ─────────────────────────────────────

    /**
     * @notice Emergency manual freeze callable by owner (e.g. court order, regulatory action).
     *         Does NOT require a valid oracle signature — owner-only override.
     * @param startupId  Target startup
     * @param reason     Human-readable reason for audit trail
     */
    function emergencyFreeze(bytes32 startupId, string calldata reason)
        external
        onlyOwner
    {
        emit FreezeTriggered(startupId, 0, reason);

        if (address(milestoneEscrow) != address(0)) {
            try milestoneEscrow.freezeMilestoneFunding(startupId, 0) {} catch {}
        }
    }

    // ── Admin: Configuration ──────────────────────────────────────────────────

    /**
     * @notice Replace the oracle signing key (e.g. after key rotation).
     * @param _signer New oracle node Ethereum address
     */
    function setOracleSigner(address _signer) external onlyOwner {
        if (_signer == address(0)) revert ZeroAddress();
        oracleSigner = _signer;
        emit OracleSignerUpdated(_signer);
    }

    /**
     * @notice Update MilestoneEscrow reference.
     * @param _escrow New escrow contract address (zero to disable routing)
     */
    function setMilestoneEscrow(address _escrow) external onlyOwner {
        milestoneEscrow = IMilestoneEscrow(_escrow);
        emit MilestoneEscrowUpdated(_escrow);
    }

    /**
     * @notice Update ComplianceRules reference.
     * @param _compliance New compliance contract address (zero to disable routing)
     */
    function setComplianceRules(address _compliance) external onlyOwner {
        complianceRules = IComplianceRules(_compliance);
        emit ComplianceRulesUpdated(_compliance);
    }

    /**
     * @notice Transfer contract ownership.
     * @param newOwner New owner address (should be a multi-sig in production)
     */
    function transferOwnership(address newOwner) external onlyOwner {
        if (newOwner == address(0)) revert ZeroAddress();
        owner = newOwner;
    }

    // ── View Functions ────────────────────────────────────────────────────────

    /**
     * @notice Get latest trust score and update time for a startup.
     * @param startupId  Startup identifier
     * @return score     Last trust score × 1000
     * @return updatedAt Timestamp of last oracle update (0 if never updated)
     */
    function getTrustScore(bytes32 startupId)
        external
        view
        returns (uint256 score, uint256 updatedAt)
    {
        return (lastTrustScore[startupId], lastUpdateTime[startupId]);
    }

    /**
     * @notice Check whether a nonce has already been used (replay detection).
     * @param nonce  The nonce to check
     * @return True if already consumed
     */
    function isNonceUsed(bytes32 nonce) external view returns (bool) {
        return usedNonces[nonce];
    }

    /**
     * @notice Verify a signature without submitting it (off-chain preview / debugging).
     * @param startupId     Startup identifier used in original signing
     * @param trustScore    Trust score × 1000 used in original signing
     * @param dataTimestamp Timestamp used in original signing
     * @param nonce         Nonce used in original signing
     * @param signature     ECDSA signature bytes
     * @return signer       Recovered signer address
     * @return valid        True if signer matches oracleSigner
     */
    function verifySignature(
        bytes32 startupId,
        uint256 trustScore,
        uint256 dataTimestamp,
        bytes32 nonce,
        bytes   calldata signature
    ) external view returns (address signer, bool valid) {
        bytes32 messageHash = keccak256(abi.encodePacked(
            startupId, trustScore, dataTimestamp, nonce
        ));
        bytes32 ethSignedHash = keccak256(abi.encodePacked(
            "\x19Ethereum Signed Message:\n32",
            messageHash
        ));
        signer = _recoverSigner(ethSignedHash, signature);
        valid  = (signer == oracleSigner);
    }

    // ── Internal Helpers ──────────────────────────────────────────────────────

    /**
     * @dev Convert trust score (×1000) to compliance score (0–100).
     *      trust 720 → compliance 72.  trust 350 → compliance 35.
     */
    function _toComplianceScore(uint256 trustScore) internal pure returns (uint8) {
        // trustScore is in [0, 1000]; map to [0, 100]
        uint256 scaled = (trustScore * 100) / TRUST_SCALE;
        return uint8(scaled > 100 ? 100 : scaled);
    }

    /**
     * @dev ECDSA signature recovery (r, s, v components, no SafeMath needed in 0.8.x).
     */
    function _recoverSigner(bytes32 hash, bytes calldata sig)
        internal
        pure
        returns (address)
    {
        require(sig.length == 65, "TrustOracle: invalid signature length");

        bytes32 r;
        bytes32 s;
        uint8   v;

        assembly {
            r := calldataload(sig.offset)
            s := calldataload(add(sig.offset, 32))
            v := byte(0, calldataload(add(sig.offset, 64)))
        }

        // Normalise v (some signers return 0/1 instead of 27/28)
        if (v < 27) v += 27;
        require(v == 27 || v == 28, "TrustOracle: invalid v value");

        return ecrecover(hash, v, r, s);
    }
}

